impl.spec_text:
spec fn polytestfun<A>(a: A, f: spec_fn(A, A) -> A) -> A{
    f(a, a)
}

proof fn testfun<A>(a: A, b: bool) {
    let aa = polytestfun(a, |x: A, y: A| (if b { x } else { y }));
    assert(!equal(a, aa)); // FAILS
}

